def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0.0
        temp_sum = 0.0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    factor = ((ratio - a) ** 6) / (a * b * 1.1 + 0.5)
                    temp_sum += factor * np.sin(ratio * b / (a + 0.5))
            priority += temp_sum ** 1.7 + np.tanh(ratio - 7) * 12
            temp_sum = 0.0
        elif 4 <= ratio <= 7:
            for m in range(2, int(np.ceil(ratio)) + 4):
                for n in range(1, m + 3):
                    val = ((ratio - m) ** 4) * np.cos(ratio * m * 1.1) / (n + 1.2)
                    priority += np.tanh(val) * 1.5
            priority += np.sqrt(ratio) * 15 - np.tanh(ratio - 4) * 3.2
        elif 2 <= ratio < 4:
            s1 = 0.0
            for r in range(1, 16):
                s1 += ((ratio - 2) ** r) / (r * 2.0) * np.sin(r * 1.2 * ratio)
            priority = s1 * np.cos(8 * ratio) - np.log(ratio + 0.1) * 7 + np.tanh(5 * (4 - ratio)) * 2.0
        elif 1 <= ratio < 2:
            s2 = 0.0
            for n in range(1, 13):
                s2 += ((2 - ratio) ** n) / (n ** 2 + 1) * np.cos(n * 1.5 * ratio)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 1)) * 5.2
            else:
                penalty = np.cos(25 * ratio) * 3.2
            priority = s2 + penalty + np.exp(-2.0 / (ratio + 0.1))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 1.2) * ((ratio - 1) ** m) / (m + 0.5)
        elif 0.5 <= ratio < 1:
            s3 = 0.0
            for n in range(1, 18):
                s3 += ((1 - ratio) ** n) / (n * 3.8)
            priority = s3
            if (i + int(item * 1.7)) % 5 == 1:
                priority *= np.log1p(bin_cap + 4) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 1.8)
            for j in range(1, 7):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.7) * 1.1
        elif 0.2 <= ratio < 0.5:
            s4 = 0.0
            for k in range(1, 15):
                s4 += ((0.5 - ratio) ** k) / (k * 3.7) * np.cos(k * ratio * 2.3)
            priority = s4 + 1 / (bin_cap + 4)
            if int(item * 1.5) % 5 == 1:
                priority *= 3.1
            else:
                priority /= 3.1
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.4) * 4.1
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.5)
        else:
            s5 = 0.0
            for t in range(1, 12):
                s5 += ((0.2 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s5 + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 2:
                priority *= 3.7
            else:
                priority /= 3.7
            if bin_cap < item * 0.18:
                priority += np.log1p(item * bin_cap) * 7.2
            else:
                priority -= np.exp(-ratio * 2.5) * 5.3
            for u in range(1, 10):
                priority += ((0.2 - ratio) ** u) / (u * 8) * np.cos(item * u * 1.2)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 7.0
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 6.2
        for idx in range(1, 6):
            if (i + idx) % 4 == 1:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.45
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.45
        if i % 4 == 1:
            priority += np.sin(ratio * i * 1.5) * 0.85
        else:
            priority -= np.cos(ratio * i * 1.5) * 0.85
        if bin_cap % 2 == 0:
            for z in range(1, 4):
                priority += np.tanh(np.sin(ratio * z * i)) * 0.3
        else:
            for z in range(1, 4):
                priority -= np.tanh(np.cos(ratio * z * i)) * 0.3
        priorities[i] = priority
    return priorities
